  @ffi.Uint64()
  external int frames_processed;

  /// reserved; xrun detection lands later (0)
  @ffi.Uint32()
  external int xrun_count;

  /// 0..1
  @ffi.Float()
  external double input_rms;

  /// 0..1
  @ffi.Float()
  external double input_peak;

  /// 0..1
  @ffi.Float()
  external double output_rms;

  /// le_latency_state
  @ffi.Int32()
  external int latency_state;

  /// valid when latency_state == LE_LATENCY_DONE
  @ffi.Double()
  external double measured_latency_ms;

  /// 0 until the first recording is finalized
  @ffi.Int32()
  external int master_length_frames;

  /// current loop playhead
  @ffi.Int32()
  external int master_position_frames;

  /// Record-offset latency compensation (frames). Recorded/overdubbed input is
  /// written this many frames earlier in the loop so it aligns with what the
  /// player heard. Auto-set by a latency measurement; manually overridable.
  @ffi.Int32()
  external int record_offset_frames;

  /// number of usable tracks (<= LE_MAX_TRACKS)
  @ffi.Int32()
  external int track_count;

  @ffi.Array.multi([8])
  external ffi.Array<le_track_snapshot> tracks;
}

final class le_engine extends ffi.Opaque {}

const int LE_MAX_CHANNELS = 32;

const int LE_MAX_TRACKS = 8;

const int LE_VIZ_POINTS = 512;
